INSERT INTO `news_article`(`article_id`, `publish_ts`, `title`, `content`, `source`, `sector_tag`, `ai_summary`, `summarized`, `ai_sentiment`, `sentiment_score`, `sentiment_done`, `ai_extract`, `extracted`, `ai_method`) VALUES
  ('INV001', '2026-04-01 09:01:00', '多资产配置关注久期、红利与黄金避险', '多家机构认为通胀回落和政策利率见顶有利于中长期债券和高质量权益资产。投资组合更强调分散配置，黄金和现金缓冲仍用于应对地缘风险与市场波动。', '全球资产观察', '宏观配置', NULL, 0, NULL, NULL, 0, NULL, 0, 'PENDING'),
  ('INV002', '2026-04-02 09:02:00', '银行红利策略回暖，息差与信用成本边际改善', '银行板块受到收益型资金重新关注。存款成本压力缓和、贷款重定价逐步体现，部分大型银行资本充足率稳定，分红和回购预期增强。', '机构银行周刊', '银行', NULL, 0, NULL, NULL, 0, NULL, 0, 'PENDING'),
  ('INV003', '2026-04-03 09:03:00', 'AI半导体产业链从GPU扩展至存储、封装与网络', 'AI算力投资进入扩散阶段，高带宽存储、先进封装、光模块和电源管理需求提升。机构提示估值分化加大，需关注订单确定性和产能稀缺性。', '科技投资日报', '半导体', NULL, 0, NULL, NULL, 0, NULL, 0, 'PENDING'),
  ('INV004', '2026-04-04 09:04:00', '新能源投资从产能扩张转向盈利质量与出海执行', '新能源行业仍具长期空间，但市场更关注现金流、海外交付和电网接入能力。储能集成、逆变器和输配电设备成为更稳定的投资线索。', '清洁能源资本', '新能源', NULL, 0, NULL, NULL, 0, NULL, 0, 'PENDING'),
  ('INV005', '2026-04-05 09:05:00', '消费复苏呈现结构分化，服务体验类需求更强', '旅游、餐饮、运动赛事和会员制零售表现较好，耐用品和低端可选消费仍偏谨慎。企业能否维持毛利率和复购率成为选股关键。', '亚洲消费策略', '消费', NULL, 0, NULL, NULL, 0, NULL, 0, 'PENDING');
